{
  "shots": [
    {
      "shot_id": "SH12",
      "priority": "P0",
      "intent": "承接樱子上一镜的追问，让美咲以唯一主动说话人的身份给出核心回答：彩花的选择出于爱，但这条牺牲循环必须从她们这里切断。",
      "duration_sec": 5,
      "shot_type": "双人近景",
      "movement": "固定机位",
      "framing_focus": "单一稳定首帧：竖屏9:16佐藤家客厅双人近景，佐藤美咲坐在沙发右侧边缘偏中央作为视觉中心，正侧脸朝向窗边，嘴部轮廓清楚，右手已经轻放在佐藤樱子发顶一侧；佐藤樱子站在沙发左前方靠窗位置，三分之二侧脸可见，右手仍轻贴美咲灰色外套袖口，嘴唇自然闭合；深灰色行李箱与旧米色彩花旧化妆盒静置在木地板前景，灰白色窗帘在樱子身后小幅摆动，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "action_intent": "佐藤美咲作为唯一主动说话人，保持坐姿稳定，眼神从窗帘方向慢慢回到樱子，轻轻摇头，指尖轻抚樱子发丝一次后说出回答；佐藤樱子全程安静倾听，嘴唇自然闭合。",
      "emotion_intent": "美咲克制悲伤但坚定守护，樱子的紧张逐渐转向信任。",
      "scene_id": "EP20_SATO_LIVING_ROOM",
      "scene_name": "佐藤家客厅",
      "dialogue": [
        {
          "speaker": "佐藤美咲",
          "text": "因为爱。但错了。我们断它。从今开始。",
          "purpose": "回答樱子对母亲选择的追问，并明确切断牺牲循环的决定。",
          "source": "onscreen",
          "listener": "佐藤樱子"
        }
      ],
      "narration": [],
      "subtitle": [
        "因为爱。但错了。我们断它。从今开始。"
      ],
      "positive_core": "单一稳定首帧：竖屏9:16佐藤家客厅近景，佐藤美咲坐在沙发右侧边缘偏中央，正侧脸和嘴部清楚可见，目光停在窗边灰白色窗帘方向，右手轻放在佐藤樱子发顶一侧；佐藤樱子站在左侧靠窗位置，三分之二侧脸可见，右手轻贴美咲灰色外套袖口，安静望向美咲；深灰色行李箱和旧米色彩花旧化妆盒固定在木地板前景，人物衣着完整，保持日常社交距离，朴素克制呈现。镜头过程中，美咲以很小幅度回看樱子，轻抚发丝一次，低声说出“因为爱。但错了。我们断它。从今开始。”樱子只用眼神回应，灰白色窗帘受室内微风轻微摆动，低饱和写实电影感，真实室内光影。",
      "first_frame_contract": {
        "location": "佐藤家客厅",
        "visual_center": "佐藤美咲的正侧脸、清楚嘴部与轻放在樱子发顶一侧的手",
        "visible_characters": [
          "佐藤美咲",
          "佐藤樱子"
        ],
        "character_positions": {
          "佐藤美咲": "画面右侧偏中央，坐在沙发右侧边缘，身体朝向樱子与窗边之间",
          "佐藤樱子": "画面左侧靠窗位置，站在沙发左前方，右手轻贴美咲灰色外套袖口"
        },
        "character_face_visibility": {
          "佐藤美咲": "脸部可见，正侧脸朝向窗边，眼睛、鼻梁、嘴部轮廓清楚，可见五官和眼神",
          "佐藤樱子": "脸部可见，三分之二侧脸朝向美咲，眼睛、鼻梁和嘴部清楚，可见五官和眼神"
        },
        "key_props": [
          "MISAKI_LUGGAGE_CASE_EP20",
          "AYAKA_OLD_MAKEUP_BOX_EP20",
          "SATO_LIVING_ROOM_CURTAIN_EP20"
