          },
          {
            "prop_id": "SATO_LIVING_ROOM_CURTAIN_EP20",
            "position": "首帧位于樱子身后窗边，覆盖窗面但不遮挡人物脸部",
            "first_frame_visible": true,
            "motion_policy": "受室内微风产生小幅摆动",
            "controlled_by": "none",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "数量固定为1组，画面只使用同一组灰白色双片落地窗帘",
            "flip_policy": "not_applicable"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "none",
          "screen_content_visible": false
        }
      },
      "source_basis": "对应TARGET_FACTS 11：樱子靠近并追问母亲选择的原因后，美咲回避目光转向窗外，轻抚樱子发丝，回答那是爱但也是错误，并决定从现在切断循环。"
    }
  ],
  "qa_report": [
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "仅生成SH12一个镜头，时长5秒；本镜头任务为dialogue，只有佐藤美咲一名onscreen主动说话人。"
    },
    {
      "check": "first frame stability",
      "result": "pass",
      "notes": "首帧为佐藤家客厅单一稳定状态，两名可见角色均露出脸部，主动说话人美咲的脸和嘴部清楚可见。"
    },
    {
      "check": "continuity from SH11",
      "result": "pass",
      "notes": "延续樱子靠近美咲并轻触袖口的状态，保持同一客厅、同一人物位置关系，以及行李箱、化妆盒、窗帘的连续性。"
    },
